var hasAllCodes = function(s, k) {
    const need = 1 << k;
    const seen = new Set();
    for (let i = 0; i <= s.length - k; i++) {
        seen.add(s.substring(i, i + k));
        if (seen.size === need) return true;
    }
    return false;
};
